import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    config_dict = {}

    def recursive_parse(element, current_dict):
        for child in element:
            if len(child) > 0:
                current_dict[child.tag] = {}
                recursive_parse(child, current_dict[child.tag])
            else:
                current_dict[child.tag] = child.text

    recursive_parse(root, config_dict)
    return config_dict